// [function] Consolidated Startup Queries
// Sends all initial queries in a timed sequence.

function buildQuery(msgType, deviceId = 1) {
    const buffer = Buffer.alloc(7);
    buffer[0] = 0xE0;
    buffer[1] = 0x31;
    buffer.writeUInt16LE(3, 2); // Data Length
    buffer[4] = msgType;
    buffer.writeUInt16LE(deviceId, 5);
    return { payload: buffer };
}

