function buildQuery(msgType, deviceId = 1) {
    const buffer = Buffer.alloc(7);
    buffer[0] = 0xE0;
    buffer[1] = 0x31;
    buffer.writeUInt16LE(3, 2); 
    buffer[4] = msgType; 
    buffer.writeUInt16LE(deviceId, 5); 
    return { payload: buffer };
}

function buildHeartbeat() {
    const buffer = Buffer.alloc(7);
    buffer[0] = 0xE0;
    buffer[1] = 0x31;
    buffer.writeUInt16LE(3, 2);
    buffer[4] = 0x01;
    buffer[5] = 0xAA;
    buffer[6] = 0xFF;
    return { payload: buffer };
}

let count = context.get("pollCounter") || 0;
count++;

// --- Every 10 seconds (Runs on every tick) ---
node.send(buildQuery(0x0F, 1)); // 1. Get Shunt Status (Type 15)

// --- Every 30 seconds (Runs on tick 3, 6, 9...) ---
if (count % 3 === 0) {
    node.log("Sending 30s poll pack");

    node.send(buildHeartbeat());         // 1. Heartbeat (Type 1)
    node.send(buildQuery(0x03, 1)); // 2. Get Comm Status (Type 3) <-- ADDED THIS
    node.send(buildQuery(0x13, 1)); // 3. Get Device Summary (Type 19)
    node.send(buildQuery(0x09, 1)); // 4. Get All Controls (Type 9)
    node.send(buildQuery(0x05, 1)); // 5. Get All Diag Alarms (Type 5)
}

if (count >= 3) {
    count = 0; 
}
context.set("pollCounter", count);

return null;

