// [function] Decode Control In-Use (Type 25)
// This decodes which control points are available.

const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const point_count = buf.readUInt16LE(7);

// This is the same map from your output nodes
const outputMap = {
    1: "Relay_1",
    2: "Relay_2",
    3: "Relay_3",
    4: "Relay_4",
    5: "OptRelay_1",
    6: "OptRelay_2",
    7: "OptRelay_3",
    8: "OptRelay_4"
};

let in_use_controls = [];

// Loop through each point in the bitmask
for (let i = 0; i < point_count; i++) {
    const point = i + 1;
    const byte_index = 9 + Math.floor(i / 8);
    const bit_index = i % 8;

    if (byte_index >= buf.length) break;

    const byte = buf[byte_index];
    const isInUse = (byte >> bit_index) & 0x01;

    if (isInUse) {
        const name = outputMap[point] || `Output_${point}`;
        in_use_controls.push({
            point: point,
            name: name
        });
    }
}

node.status(`${in_use_controls.length} controls in use`);

msg.payload = {
    type: "ControlInUse",
    device: devAddr,
    in_use_controls: in_use_controls
};

return msg;

// [function] Decode Filter Alarms (Type 17)
// This node now sends ONE message with an ARRAY of all statuses
// to prevent a race condition downstream.

const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const point_count = buf.readUInt16LE(7);

let all_point_statuses = []; // This will be the new payload
let point = 1;

// Loop through the data bytes. Each byte holds 4 points (2 bits each).
for (let byte_index = 9; byte_index < buf.length; byte_index++) {
    const byte = buf[byte_index];

    for (let i = 0; i < 4; i++) { // 4 points per byte
        if (point > point_count) break;

        const state = (byte >> (i * 2)) & 0x03; // Get the 2 bits for this point
        const is_alarm = (state & 0x01) > 0;
        const is_tamper = (state & 0x02) > 0;

        // --- This description logic MUST match your other decoders ---
        let description = `Point ${point}`;
        let zone_num = null;
        if (point === 1) {
            description = "AuxInput_1";
        } else if (point === 2) {
            description = "AuxInput_2";
        } else if (point >= 3 && point <= 62) {
            zone_num = point - 2;
            description = `Zone_${zone_num}`;
        } else if (point >= 71 && point <= 74) {
            description = `OptInput_${point - 70}`;
        }

        let status_string = "Secure";
        if (is_alarm) {
            status_string = "Alarm (Hold)"; // No location info in this msg
        } else if (is_tamper) {
            status_string = "Tamper/Supervision";
        }

        all_point_statuses.push({
            "type": "SensorAlarm (Filtered)", // Use same type as Type 16
            "description": description,
            "device": devAddr,
            "point_raw": point,
            "zone": zone_num,
            "status_raw": state,
            "status_string": status_string,
            "alarm": is_alarm,
            "tamper": is_tamper,
            "location_count": 0,
            "locations": [],
            "timestamp": new Date().toISOString()
        });

        point++; // Move to the next point
    }
    if (point > point_count) break;
}

node.status(`${all_point_statuses.length} points processed`);

// Send a SINGLE message with a new type and the full array
msg.payload = {
    type: "FilteredAlarmList",
    points: all_point_statuses
};

return msg;

// [function] Decode Range Alarms (Type 26)
const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const numRanges = buf.readUInt16LE(7);

let messages_to_send = [];

if (numRanges === 0 || numRanges === 0xFFFF) {
    node.warn(`Device ${devAddr} reports no range information.`);
    return null;
}

let offset = 9; // Start of first range structure

for (let i = 0; i < numRanges; i++) {
    if (offset + 11 > buf.length) {
        node.warn("Buffer overflow reading range data");
        break;
    }

    const point_num = buf.readUInt16LE(offset);       // Bytes 10-11
    // Byte 12 is 'side', we skip it (offset + 2)
    const range_start = buf.readUInt32LE(offset + 3); // Bytes 13-16
    const range_end = buf.readUInt32LE(offset + 7);   // Bytes 17-20

    // Use your existing logic: Zone_1 = point 3, Zone_2 = point 4
    if (point_num >= 3) { 
        const zone_id = "Zone_" + (point_num - 2);

        const sql_query = `
            UPDATE zones 
            SET 
                meter_start = ${range_start}, 
                meter_end = ${range_end} 
            WHERE 
                zone_id = '${zone_id}';
        `;

        messages_to_send.push({
            query: sql_query,
            payload: null,
            topic: `${zone_id} range: ${range_start}-${range_end}`
        });
    }

    offset += 11; // Move to the next range structure
}

if (messages_to_send.length > 0) {
    node.warn(`Found ${messages_to_send.length} zone ranges to update.`);
    return [ messages_to_send ]; // Send all messages
}

return null;
